INSERT INTO hub_config (config_key, config_value) VALUES ('processos', '[{"id": "p1", "titulo": "Como calcular preco de venda", "categoria": "vendas", "conteudo": "1. Abra a Calculadora de Precos\n2. Insira o custo do produto\n3. Defina a margem desejada\n   Varejo: 35% | Atacarejo: 20%\n4. O sistema aplica automaticamente:\n   Encargos fixos 22,18% + Taxa cartao 6% = 28,18%\n5. Preco = Custo / (1 - Margem% - 28,18%)", "autor": "Murilo", "criadoEm": "2026-04-01", "atualizadoEm": "2026-04-20"}, {"id": "p2", "titulo": "Politica de troca de mercadorias", "categoria": "logistica", "conteudo": "1. Prazo maximo: 7 dias apos a compra\n2. Produto deve estar lacrado e sem uso\n3. Cliente apresenta nota fiscal\n4. Gerente autoriza a troca\n5. Registrar no Tiny como devolucao\n6. Emitir nova NF para o produto trocado", "autor": "Murilo", "criadoEm": "2026-04-05", "atualizadoEm": "2026-04-05"}, {"id": "p3", "titulo": "Linha Impala - Guia de Produtos", "categoria": "produtos", "conteudo": "**Esmaltes Basicos:** 8ml, 200+ cores, custo R$4-8\n**Esmaltes Premium:** 10ml, acabamentos especiais, custo R$8-15\n**Base Coat:** protecao, custo R$6-10\n**Top Coat:** brilho e fixacao, custo R$6-10\n\nDiferenciais: formula livre de tolueno, secagem rapida\nPublico: saloes, manicures, consumidor final\nEstoque minimo: 50 unidades por categoria", "autor": "Murilo", "criadoEm": "2026-04-10", "atualizadoEm": "2026-04-10"}, {"id": "p4", "titulo": "Fluxo de cobranca de boletos", "categoria": "financeiro", "conteudo": "D-5: Enviar lembrete por WhatsApp\nD-2: Ligar para confirmar pagamento\nD+1: Contato para verificar\nD+3: Notificar gerencia e bloquear novos pedidos\nD+7: Encaminhar para cobranca formal", "autor": "Murilo", "criadoEm": "2026-04-12", "atualizadoEm": "2026-04-12"}, {"id": "p5", "titulo": "Admissao CLT - Documentos", "categoria": "rh", "conteudo": "Documentos: RG, CPF, CTPS, comprovante residencia, foto 3x4\nExame admissional obrigatorio\nRegistro na CTPS em ate 48h\nCadastro no ponto eletronico\nTreinamento inicial: 3 dias com supervisor\nExperiencia: 45 + 45 dias", "autor": "Murilo", "criadoEm": "2026-04-15", "atualizadoEm": "2026-04-15"}]') ON CONFLICT (config_key) DO UPDATE SET config_value = EXCLUDED.config_value;
